const incoming = $input.first().json;
const payload = incoming.body && typeof incoming.body === 'object' ? incoming.body : incoming;
const domain = String(process.env.MAKESHOP_DOMAIN || 'foreverlove.co.kr').trim();
const shopkey = String(process.env.MAKESHOP_SHOPKEY || '').trim();
const licensekey = String(process.env.MAKESHOP_LICENSEKEY || '').trim();
if (!shopkey || !licensekey) {
  throw new Error('MAKESHOP_SHOPKEY / MAKESHOP_LICENSEKEY 이 설정되지 않았습니다.');
}
const mode = String(payload.mode || 'DRY_RUN').trim().toUpperCase();
const items = Array.isArray(payload.items) ? payload.items : [];
if (!items.length) {
  throw new Error('보낼 항목이 없습니다.');
}
const baseUrl = `https://${domain}`;
const out = items.map((raw) => {
  const sourcePayload = raw.sourcePayload && typeof raw.sourcePayload === 'object' ? raw.sourcePayload : {};
  const sourceKind = String(raw.sourceKind || raw.itemType || 'crm_board').trim();
  const reply = String(raw.reply || '').trim();
  if (!reply) {
    throw new Error(`reply_content_missing:${raw.id || 'unknown'}`);
  }
  if (sourceKind === 'review' || raw.itemType === 'review') {
    return {
      json: {
        original_id: String(raw.id || sourcePayload.uid || '').trim(),
        mode,
        should_send: mode === 'LIVE_SEND',
        request_url: `${baseUrl}/list/open_api_process.html?mode=save&type=review&process=store`,
        request_form: {
          uid: String(sourcePayload.uid || raw.id || '').trim(),
          save_type: 'answer',
          reply_content: reply,
        },
        source_kind: 'review',
        shopkey,
        licensekey,
      }
    };
  }
  const date = String(sourcePayload.date || raw.receivedAt || '').trim().replace('T', ' ').replace(/\+09:00$/, '');
  if (!date) {
    throw new Error(`crm_board_date_missing:${raw.id || 'unknown'}`);
  }
  const form = {
    'datas[0][date]': date,
    'datas[0][reply_content]': reply,
    'datas[0][send_email]': 'N',
    'datas[0][send_sms]': 'N',
  };
  if (sourcePayload.userid) {
    form['datas[0][userid]'] = String(sourcePayload.userid);
  }
  return {
    json: {
      original_id: String(raw.id || '').trim(),
      mode,
      should_send: mode === 'LIVE_SEND',
      request_url: `${baseUrl}/list/open_api_process.html?mode=save&type=crm_board&process=reply`,
      request_form: form,
      source_kind: 'crm_board',
      shopkey,
      licensekey,
    }
  };
});
return out;

const original = $('요청 payload 검증').item.json;
return [{ json: { result: {
  id: original.original_id,
  ok: true,
  message: 'DRY_RUN 완료',
  externalStatus: 'OPEN',
  statusCode: 200,
  dispatchMode: original.mode,
} } }];

const original = $('요청 payload 검증').item.json;
const body = $json || {};
const returnCode = String(body.return_code || body.code || '').trim();
const ok = !returnCode || returnCode === '0000';
const message = ok ? 'LIVE_SEND 완료' : String(body.message || body.error || body.return_message || returnCode || 'send_failed');
return [{ json: { result: {
  id: original.original_id,
  ok,
  message,
  externalStatus: ok ? 'ANSWERED' : 'OPEN',
  statusCode: ok ? 200 : 500,
  dispatchMode: original.mode,
} } }];

const dry = $('DRY_RUN 결과').all().map((item) => item.json.result).filter(Boolean);
const live = $('LIVE_SEND 결과').all().map((item) => item.json.result).filter(Boolean);
const results = [...dry, ...live];
const dispatchMode = results[0] ? results[0].dispatchMode : 'UNKNOWN';
return [{ json: {
  results,
  meta: {
    channel: 'makeshop',
    mode: dispatchMode,
    totalCount: results.length,
  }
} }];
